 18→class BloggingPromptCardViewHolder(
 19→    parent: ViewGroup,
 20→    private val uiHelpers: UiHelpers,
 21→    private val bloggingPromptsCardAnalyticsTracker: BloggingPromptsCardAnalyticsTracker,
 22→    private val htmlCompatWrapper: HtmlCompatWrapper,
 23→    private val learnMoreClicked: () -> Unit
 24→) : MySiteCardAndItemViewHolder<MySiteBloggingPromptCardBinding>(
 25→    parent.viewBinding(MySiteBloggingPromptCardBinding::inflate)
 26→) {
 27→    fun bind(card: BloggingPromptCardWithData) = with(binding) {
 28→        val cardPrompt = htmlCompatWrapper.fromHtml(
 29→            uiHelpers.getTextOfUiString(promptContent.context, card.prompt).toString()
 30→        )
 31→        uiHelpers.setTextOrHide(promptContent, cardPrompt)
 32→        uiHelpers.updateVisibility(answerButton, !card.isAnswered)
 33→
 34→        setupAttributionContainer(card.attribution)
 35→
 36→        bloggingPromptCardMenu.setOnClickListener {
 37→            bloggingPromptsCardAnalyticsTracker.trackMySiteCardMenuClicked()
 38→            showCardMenu(card)
 39→        }
 40→
 41→        answerButton.setOnClickListener {
 42→            card.onAnswerClick.invoke(card.promptId)
 43→        }
 44→        shareButton.setOnClickListener {
 45→            bloggingPromptsCardAnalyticsTracker.trackMySiteCardShareClicked()
 46→            card.onShareClick.invoke(
 47→                uiHelpers.getTextOfUiString(
 48→                    shareButton.context,
 49→                    card.prompt
 50→                ).toString()
 51→            )
 52→        }
 53→        uiHelpers.updateVisibility(answeredPromptControls, card.isAnswered)
 54→
 55→        setupAnsweredUsersContainer(card)
 56→    }
 57→
 58→    private fun MySiteBloggingPromptCardBinding.setupAttributionContainer(
 59→        attribution: BloggingPromptAttribution
 60→    ) {
 61→        uiHelpers.updateVisibility(attributionContainer, attribution != NO_ATTRIBUTION)
 62→
 63→        val context = attributionContainer.context
 64→
 65→        attribution.contentRes
 66→            .takeIf { it != -1 }
 67→            ?.let { context.getString(it) }
 68→            ?.let { content ->
 69→                attributionContent.text = htmlCompatWrapper.fromHtml(content)
 70→            }
 71→
 72→        attribution.iconRes
 73→            .takeIf { it != -1 }
 74→            ?.let { iconRes ->
 75→                attributionIcon.setImageResource(iconRes)
 76→            }
 77→    }
 78→
 79→    @Suppress("NestedBlockDepth")
 80→    private fun setupAnsweredUsersContainer(
 81→        card: BloggingPromptCardWithData,
 82→    ) = with(binding) {
 83→        if (card.numberOfAnswers <= 0) {
 84→            answeredUsersAvatars.isVisible = false
 85→            answeredUsersLabel.isVisible = false
 86→            return@with
 87→        }
 88→
 89→        answeredUsersAvatars.apply {
 90→            isVisible = true
 91→            avatars = card.respondents
 92→                .filterIsInstance(TrainOfAvatarsItem.AvatarItem::class.java)
 93→        }
 94→
 95→        answeredUsersLabel.apply {
 96→            card.respondents
 97→                .filterIsInstance(TrainOfAvatarsItem.TrailingLabelTextItem::class.java)
 98→                .firstOrNull()
 99→                ?.let {
100→                    isVisible = true
101→                    text = uiHelpers.getTextOfUiString(
102→                        context,
103→                        it.text
104→                    )
105→                    setTextColor(
106→                        context.getColorStateListFromAttributeOrRes(it.labelColor)
107→                    )
108→                    card.onViewAnswersClick?.let { onClick ->
109→                        setOnClickListener { onClick(card.tagUrl) }
110→                    }
111→                }
112→                ?: run {
113→                    isVisible = false
114→                }
115→        }
116→    }
117→
118→    private fun MySiteBloggingPromptCardBinding.showCardMenu(card: BloggingPromptCardWithData) {
119→        PopupMenu(bloggingPromptCardMenu.context, bloggingPromptCardMenu).apply {
120→            setOnMenuItemClickListener {
121→                when (it.itemId) {
122→                    R.id.view_more -> {
123→                        bloggingPromptsCardAnalyticsTracker.trackMySiteCardMenuViewMorePromptsClicked()
124→                        card.onViewMoreClick.invoke()
125→                    }
126→
127→                    R.id.skip -> {
128→                        bloggingPromptsCardAnalyticsTracker.trackMySiteCardMenuSkipThisPromptClicked()
129→                        card.onSkipClick.invoke()
130→                    }
131→
132→                    R.id.remove -> {
133→                        bloggingPromptsCardAnalyticsTracker.trackMySiteCardMenuRemoveFromDashboardClicked()
134→                        card.onRemoveClick.invoke()
135→                    }
136→
137→                    R.id.learn_more -> {
138→                        bloggingPromptsCardAnalyticsTracker.trackMySiteCardMenuLearnMoreClicked()
139→                        learnMoreClicked()
140→                    }
141→                }
142→                return@setOnMenuItemClickListener true
143→            }
144→            inflate(R.menu.blogging_prompt_card_menu)
145→            MenuCompat.setGroupDividerEnabled(menu, true)
146→        }.also {
147→            it.show()
148→        }
149→    }
150→}
