 58→    @NonNull
 59→    public static Intent buildReaderPostDetailIntent(Context context, boolean isFeed, long blogId, long postId,
 60→                                                      DirectOperation directOperation, int commentId,
 61→                                                      boolean isRelatedPost, String interceptedUri) {
 62→        Intent intent = new Intent(context, ReaderPostPagerActivity.class);
 63→        intent.putExtra(ReaderConstants.ARG_IS_FEED, isFeed);
 64→        intent.putExtra(ReaderConstants.ARG_BLOG_ID, blogId);
 65→        intent.putExtra(ReaderConstants.ARG_POST_ID, postId);
 66→        intent.putExtra(ReaderConstants.ARG_DIRECT_OPERATION, directOperation);
 67→        intent.putExtra(ReaderConstants.ARG_COMMENT_ID, commentId);
 68→        intent.putExtra(ReaderConstants.ARG_IS_SINGLE_POST, true);
 69→        intent.putExtra(ReaderConstants.ARG_IS_RELATED_POST, isRelatedPost);
 70→        intent.putExtra(ReaderConstants.ARG_INTERCEPTED_URI, interceptedUri);
 71→        return intent;
 72→    }
