128→        if (ReaderUtils.isExternalFeed(siteId, feedId)) {
129→            intent.putExtra(ReaderConstants.ARG_FEED_ID, feedId);
130→            intent.putExtra(ReaderConstants.ARG_IS_FEED, true);
131→        } else {
132→            intent.putExtra(ReaderConstants.ARG_BLOG_ID, siteId);
