2349→        }
2350→        new Thread() {
2351→            @Override
2352→            public void run() {
2353→                if (ReaderTagTable.shouldAutoUpdateTag(getCurrentTag()) && isAdded()) {
2354→                    getActivity().runOnUiThread(new Runnable() {
2355→                        @Override
2356→                        public void run() {
