2372→    private void showLoadingProgress(boolean showProgress) {
2373→        if (isAdded() && mProgress != null) {
2374→            if (showProgress) {
2375→                mProgress.bringToFront();
2376→                mProgress.setVisibility(View.VISIBLE);
2377→            } else {
2378→                mProgress.setVisibility(View.GONE);
2379→            }
