 87→    public static ReaderPost fromJson(JSONObject json) {
 88→        if (json == null) {
 89→            throw new IllegalArgumentException("null json post");
 90→        }
 91→
 92→        ReaderPost post = new ReaderPost();
 93→
 94→        post.postId = json.optLong(ReaderConstants.POST_ID);
 95→        post.blogId = json.optLong(ReaderConstants.POST_SITE_ID);
 96→        post.feedId = json.optLong("feed_ID");
 97→        post.feedItemId = json.optLong("feed_item_ID");
 98→
 99→        if (json.has(ReaderConstants.POST_PSEUDO_ID)) {
100→            post.mPseudoId = JSONUtils.getString(json, ReaderConstants.POST_PSEUDO_ID); // read/ endpoint
101→        } else {
102→            post.mPseudoId = JSONUtils.getString(json, "global_ID"); // sites/ endpoint
103→        }
104→
105→        // remove HTML from the excerpt
106→        post.mExcerpt = HtmlUtils.fastStripHtml(JSONUtils.getString(json, "excerpt")).trim();
107→
108→        post.mText = JSONUtils.getString(json, "content");
109→        post.mTitle = JSONUtils.getStringDecoded(json, "title");
110→        post.mFormat = JSONUtils.getString(json, "format");
111→        post.mUrl = JSONUtils.getString(json, "URL");
112→        post.mShortUrl = JSONUtils.getString(json, "short_URL");
113→        post.setBlogUrl(JSONUtils.getString(json, "site_URL"));
114→
115→        post.numLikes = json.optInt("like_count");
116→        post.isLikedByCurrentUser = JSONUtils.getBool(json, "i_like");
117→        post.isFollowedByCurrentUser = JSONUtils.getBool(json, "is_following");
118→        post.isExternal = JSONUtils.getBool(json, "is_external");
119→        post.isPrivate = JSONUtils.getBool(json, "site_is_private");
120→        post.isPrivateAtomic = JSONUtils.getBool(json, "site_is_atomic");
121→        post.isJetpack = JSONUtils.getBool(json, "is_jetpack");
122→        post.useExcerpt = JSONUtils.getBool(json, "use_excerpt");
123→        post.isSeen = JSONUtils.getBool(json, "is_seen");
124→        post.isSeenSupported = json.has("is_seen");
125→
126→        JSONObject jsonDiscussion = json.optJSONObject("discussion");
127→        if (jsonDiscussion != null) {
128→            post.isCommentsOpen = JSONUtils.getBool(jsonDiscussion, "comments_open");
129→            post.numReplies = jsonDiscussion.optInt("comment_count");
130→        } else {
131→            post.isCommentsOpen = JSONUtils.getBool(json, "comments_open");
132→            post.numReplies = json.optInt("comment_count");
133→        }
134→
135→        // parse the author section
136→        assignAuthorFromJson(post, json.optJSONObject("author"));
137→
138→        post.mFeaturedImage = JSONUtils.getString(json, "featured_image");
139→        post.mBlogName = JSONUtils.getStringDecoded(json, "site_name");
140→
141→        post.mDatePublished = JSONUtils.getString(json, "date");
142→        post.mDateLiked = JSONUtils.getString(json, "date_liked");
143→        post.mDateTagged = JSONUtils.getString(json, "tagged_on");
144→
145→        // "score" only exists for search results
146→        post.score = json.optDouble("score");
147→
148→        // remove html from title (rare, but does happen)
149→        if (post.hasTitle() && post.mTitle.contains("<") && post.mTitle.contains(">")) {
150→            post.mTitle = HtmlUtils.stripHtml(post.mTitle);
151→        }
152→
153→        // parse the tags section
154→        assignTagsFromJson(post, json.optJSONObject("tags"));
155→
156→        // parse the attachments
157→        JSONObject jsonAttachments = json.optJSONObject("attachments");
158→        if (jsonAttachments != null && jsonAttachments.length() > 0) {
159→            post.mAttachmentsJson = jsonAttachments.toString();
160→        }
161→
162→        // site metadata - returned when ?meta=site was added to the request
163→        JSONObject jsonSite = JSONUtils.getJSONChild(json, "meta/data/site");
164→        if (jsonSite != null) {
165→            post.blogId = jsonSite.optInt("ID");
166→            post.mBlogName = JSONUtils.getString(jsonSite, "name");
167→            post.setBlogUrl(JSONUtils.getString(jsonSite, "URL"));
168→            post.isPrivate = JSONUtils.getBool(jsonSite, "is_private");
169→            JSONObject jsonSiteIcon = jsonSite.optJSONObject("icon");
170→            if (jsonSiteIcon != null) {
171→                post.mBlogImageUrl = JSONUtils.getString(jsonSiteIcon, "img");
172→            }
173→            // TODO: as of 29-Sept-2014, this is broken - endpoint returns false when it should be true
174→            post.isJetpack = JSONUtils.getBool(jsonSite, "jetpack");
175→
176→            post.organizationId = jsonSite.optInt("organization_id");
177→        }
178→
179→        // "discover" posts
