435→    public static ReaderTagList getOrderedTagsList(ReaderTagList tagList, Map<String, TagInfo> defaultTagInfos) {
436→        ReaderTagList orderedTagList = new ReaderTagList();
437→        Map<String, ReaderTag> defaultTags = new HashMap<>();
438→
439→        for (ReaderTag tag : tagList) {
440→            if (defaultTagFoundAndAdded(defaultTagInfos, tag, defaultTags)) continue;
441→
442→            orderedTagList.add(tag);
443→        }
444→        prependDefaults(defaultTags, orderedTagList, defaultTagInfos);
445→
446→        return orderedTagList;
447→    }
