451→            boolean isTopLevelReader,
452→            FilteredRecyclerView recyclerView
453→    ) {
454→        if (isTopLevelReader) {
455→            if (ReaderUtils.isDefaultInMemoryTag(tag)) {
456→                return true;
457→            }
458→
459→            boolean isSpecialTag = tag != null
460→                                   &&
461→                                   (tag.isDiscover() || tag.isPostsILike() || tag.isBookmarked());
462→
463→            boolean tabsInitializingNow = recyclerView != null && recyclerView.getCurrentFilter() == null;
464→
465→            boolean tagIsFollowedSitesOrAFollowedTag = tag != null
466→                                                       && (
467→                                                               tag.isFollowedSites()
468→                                                               || tag.tagType == ReaderTagType.FOLLOWED
469→                                                       );
470→
471→            if (isSpecialTag) {
472→                return false;
473→            } else if (tabsInitializingNow) {
474→                return tagIsFollowedSitesOrAFollowedTag;
475→            } else if (recyclerView != null && recyclerView.getCurrentFilter() instanceof ReaderTag) {
476→                if (recyclerView.isValidFilter(tag)) {
477→                    return tag.isFollowedSites();
478→                } else {
479→                    // If we reach here it means we are setting a followed tag or site in the Following tab
480→                    return true;
481→                }
482→            } else {
483→                return false;
484→            }
485→        } else {
486→            return tag != null && tag.isFollowedSites();
487→        }
488→    }
489→
490→    public static @NonNull ReaderTag getValidTagForSharedPrefs(
491→            @NonNull ReaderTag tag,
492→            boolean isTopLevelReader,
493→            FilteredRecyclerView recyclerView,
494→            @NonNull ReaderTag defaultTag
495→    ) {
496→        if (!isTopLevelReader) {
497→            return tag;
498→        }
499→
500→        boolean isValidFilter = (recyclerView != null && recyclerView.isValidFilter(tag));
501→        boolean isSpecialTag = tag.isDiscover() || tag.isPostsILike() || tag.isBookmarked();
502→        if (!isSpecialTag && !isValidFilter && isTagManagedInFollowingTab(tag, isTopLevelReader, recyclerView)) {
503→            return defaultTag;
504→        }
505→
506→        return tag;
507→    }
508→
509→    public static boolean isDefaultInMemoryTag(ReaderTag tag) {
510→        return tag != null && tag.isDefaultInMemoryTag();
511→    }
