513→    public static String getCommaSeparatedTagSlugs(ReaderTagList tags) {
514→        StringBuilder slugs = new StringBuilder();
515→        for (ReaderTag tag : tags) {
516→            if (slugs.length() > 0) {
517→                slugs.append(",");
518→            }
519→            final String tagNameForApi = ReaderUtils.sanitizeWithDashes(tag.getTagSlug());
520→            slugs.append(tagNameForApi);
521→        }
522→        return slugs.toString();
523→    }
524→
525→    public static ReaderTagList getTagsFromCommaSeparatedSlugs(@NonNull String commaSeparatedTagSlugs) {
526→        ReaderTagList tags = new ReaderTagList();
527→        if (!commaSeparatedTagSlugs.trim().equals("")) {
528→            for (String slug : commaSeparatedTagSlugs.split(",", -1)) {
529→                ReaderTag tag = ReaderUtils.getTagFromTagName(slug, ReaderTagType.DEFAULT);
530→                tags.add(tag);
531→            }
532→        }
533→        return tags;
534→    }
