248→    private static class HistoryStack extends Stack<String> {
249→        private final String mKeyName;
250→
251→        HistoryStack(@SuppressWarnings("SameParameterValue") String keyName) {
252→            mKeyName = keyName;
253→        }
254→
255→        void restoreInstance(Bundle bundle) {
256→            clear();
257→            if (bundle.containsKey(mKeyName)) {
258→                ArrayList<String> history = bundle.getStringArrayList(mKeyName);
259→                if (history != null) {
260→                    this.addAll(history);
261→                }
262→            }
263→        }
264→
265→        void saveInstance(Bundle bundle) {
266→            if (!isEmpty()) {
267→                ArrayList<String> history = new ArrayList<>();
268→                history.addAll(this);
269→                bundle.putStringArrayList(mKeyName, history);
270→            }
271→        }
272→    }
