326→    private void toggleFollowButton(
327→            Context context,
328→            @NonNull ReaderTag currentTag,
329→            TagHeaderViewHolder tagHolder
330→    ) {
331→        if (!NetworkUtils.checkConnection(context)) {
332→            return;
333→        }
334→
335→        final boolean isAskingToFollow = !ReaderTagTable.isFollowedTagName(currentTag.getTagSlug());
336→
337→        final String slugForTracking = currentTag.getTagSlug();
338→
339→        ReaderActions.ActionListener listener = succeeded -> {
340→            if (!succeeded) {
341→                int errResId = isAskingToFollow ? R.string.reader_toast_err_add_tag
342→                        : R.string.reader_toast_err_remove_tag;
343→                ToastUtils.showToast(context, errResId);
344→            } else {
345→                if (isAskingToFollow) {
346→                    mReaderTracker.trackTag(
347→                            AnalyticsTracker.Stat.READER_TAG_FOLLOWED,
348→                            slugForTracking,
349→                            mSource
350→                    );
351→                } else {
352→                    mReaderTracker.trackTag(
353→                            AnalyticsTracker.Stat.READER_TAG_UNFOLLOWED,
354→                            slugForTracking,
355→                            mSource
356→                    );
357→                }
358→            }
359→            renderTagHeader(currentTag, tagHolder, true);
360→        };
361→
362→        boolean success;
363→        boolean isLoggedIn = mAccountStore.hasAccessToken();
364→        if (isAskingToFollow) {
365→            success = ReaderTagActions.addTag(mCurrentTag, listener, isLoggedIn);
366→        } else {
367→            success = ReaderTagActions.deleteTag(mCurrentTag, listener, isLoggedIn);
368→        }
369→
370→        if (isLoggedIn && success) {
371→            renderTagHeader(currentTag, tagHolder, false);
372→        }
373→    }
